import React from 'react';
import {
  PortableText,
  mergeComponents,
  type PortableTextComponents,
  type PortableTextReactComponents,
} from '@portabletext/react';

import { CodeBlock } from './CodeBlock';
import { defaultTheme } from './theme';
import type { PortableTextViewProps, PortableTextTheme } from './types';

interface CodeValue {
  code: string;
  language?: string;
  filename?: string;
}

function createComponents(theme: PortableTextTheme): PortableTextComponents {
  return {
    block: {
      h1: ({ children }) => <h1 className={theme.block?.h1}>{children}</h1>,
      h2: ({ children }) => <h2 className={theme.block?.h2}>{children}</h2>,
      h3: ({ children }) => <h3 className={theme.block?.h3}>{children}</h3>,
      normal: ({ children }) => (
        <p className={theme.block?.normal}>{children}</p>
      ),
      blockquote: ({ children }) => (
        <blockquote className={theme.block?.blockquote}>
          {children}
        </blockquote>
      ),
    },

    marks: {
      link: ({ children, value }) => {
        const rel = !value?.href?.startsWith('/')
          ? 'noreferrer noopener'
          : undefined;

        return (
          <a href={value?.href} rel={rel}>
            {children}
          </a>
        );
      },
    },

    list: {
      bullet: ({ children }) => (
        <ul className={theme.list?.bullet}>{children}</ul>
      ),
      number: ({ children }) => (
        <ol className={theme.list?.number}>{children}</ol>
      ),
    },

    listItem: {
      bullet: ({ children }) => (
        <li className={theme.list?.item}>{children}</li>
      ),
      number: ({ children }) => (
        <li className={theme.list?.item}>{children}</li>
      ),
    },

    types: {
      code: ({ value }) => {
        const v = value as CodeValue;
        if (!v?.code) return null;

        return (
          <CodeBlock
            code={v.code.trim()}
            language={v.language}
            filename={v.filename}
            theme={theme}
          />
        );
      },
    },
  };
}

export function PortableTextView({
  value,
  theme = defaultTheme,
  components,
  ...props
}: PortableTextViewProps) {
  const base = createComponents(theme);
  const merged = components
    ? mergeComponents(
        base as unknown as PortableTextReactComponents,
        components as unknown as PortableTextReactComponents,
      )
    : base;

  if (!value) return <p>No content available.</p>;

  return <PortableText value={value} components={merged} {...props} />;
}