'use client';

import * as React from 'react';
import { cn } from '../cn';

interface CountdownTimerProps {
  targetDate: Date | number;
  onComplete?: () => void;
  className?: string;
  showDays?: boolean;
  showHours?: boolean;
  showMinutes?: boolean;
  showSeconds?: boolean;
  format?: 'default' | 'compact';
  size?: 'sm' | 'default' | 'lg';
}

interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

const calculateTimeLeft = (targetDate: Date | number): TimeLeft => {
  const target = new Date(targetDate).getTime();
  const now = Date.now();
  const difference = target - now;

  if (difference <= 0) {
    return { days: 0, hours: 0, minutes: 0, seconds: 0 };
  }

  return {
    days: Math.floor(difference / (1000 * 60 * 60 * 24)),
    hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
    minutes: Math.floor((difference / 1000 / 60) % 60),
    seconds: Math.floor((difference / 1000) % 60),
  };
};

const TimeUnit: React.FC<{
  value: number;
  label: string;
  format: 'default' | 'compact';
  size: 'sm' | 'default' | 'lg';
  show: boolean;
}> = ({ value, label, format, size, show }) => {
  if (!show) return null;

  const displayValue = format === 'compact' ? String(value).padStart(2, '0') : value;

  const sizeClasses = {
    sm: 'text-sm min-w-[40px]',
    default: 'text-2xl min-w-[60px]',
    lg: 'text-4xl min-w-[80px]',
  };

  return (
    <div className="flex flex-col items-center">
      <div className={cn('font-bold tabular-nums bg-muted rounded-lg p-2', sizeClasses[size])}>
        {displayValue}
      </div>
      {format === 'default' && <span className="text-xs text-muted-foreground mt-1">{label}</span>}
    </div>
  );
};

const CountdownTimer: React.FC<CountdownTimerProps> = ({
  targetDate,
  onComplete,
  className,
  showDays = true,
  showHours = true,
  showMinutes = true,
  showSeconds = true,
  format = 'default',
  size = 'default',
}) => {
  const [timeLeft, setTimeLeft] = React.useState<TimeLeft>(() => calculateTimeLeft(targetDate));
  const [isComplete, setIsComplete] = React.useState(false);

  React.useEffect(() => {
    const timer = setInterval(() => {
      const newTimeLeft = calculateTimeLeft(targetDate);
      setTimeLeft(newTimeLeft);

      if (
        newTimeLeft.days === 0 &&
        newTimeLeft.hours === 0 &&
        newTimeLeft.minutes === 0 &&
        newTimeLeft.seconds === 0
      ) {
        setIsComplete(true);
        clearInterval(timer);
        onComplete?.();
      }
    }, 1000);

    return () => clearInterval(timer);
  }, [targetDate, onComplete]);

  if (isComplete) {
    return (
      <div className={cn('flex items-center justify-center p-4', className)}>
        <span className="text-lg font-semibold text-primary">Time's up!</span>
      </div>
    );
  }

  return (
    <div className={cn('flex items-center gap-2', className)}>
      <TimeUnit value={timeLeft.days} label="Days" format={format} size={size} show={showDays} />
      {showDays && showHours && format === 'compact' && (
        <span
          className={cn(
            'font-bold',
            size === 'lg' ? 'text-4xl' : size === 'sm' ? 'text-sm' : 'text-2xl'
          )}
        >
          :
        </span>
      )}
      <TimeUnit value={timeLeft.hours} label="Hours" format={format} size={size} show={showHours} />
      {showHours && showMinutes && format === 'compact' && (
        <span
          className={cn(
            'font-bold',
            size === 'lg' ? 'text-4xl' : size === 'sm' ? 'text-sm' : 'text-2xl'
          )}
        >
          :
        </span>
      )}
      <TimeUnit
        value={timeLeft.minutes}
        label="Minutes"
        format={format}
        size={size}
        show={showMinutes}
      />
      {showMinutes && showSeconds && format === 'compact' && (
        <span
          className={cn(
            'font-bold',
            size === 'lg' ? 'text-4xl' : size === 'sm' ? 'text-sm' : 'text-2xl'
          )}
        >
          :
        </span>
      )}
      <TimeUnit
        value={timeLeft.seconds}
        label="Seconds"
        format={format}
        size={size}
        show={showSeconds}
      />
    </div>
  );
};

interface CountUpTimerProps {
  className?: string;
  size?: 'sm' | 'default' | 'lg';
  format?: 'default' | 'compact';
  onReset?: () => void;
}

const CountUpTimer: React.FC<CountUpTimerProps> = ({
  className,
  size = 'default',
  format = 'default',
}) => {
  const [seconds, setSeconds] = React.useState(0);
  const [isRunning, setIsRunning] = React.useState(true);

  React.useEffect(() => {
    if (!isRunning) return;

    const interval = setInterval(() => {
      setSeconds(s => s + 1);
    }, 1000);

    return () => clearInterval(interval);
  }, [isRunning]);

  const hours = Math.floor(seconds / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const secs = seconds % 60;

  const sizeClasses = {
    sm: 'text-sm',
    default: 'text-2xl',
    lg: 'text-4xl',
  };

  const displayTime =
    format === 'compact'
      ? `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(secs).padStart(2, '0')}`
      : `${hours}h ${minutes}m ${secs}s`;

  return (
    <div className={cn('flex items-center gap-2', className)}>
      <div className={cn('font-bold tabular-nums', sizeClasses[size])}>{displayTime}</div>
      <button
        onClick={() => setIsRunning(!isRunning)}
        className="text-xs text-muted-foreground hover:text-primary"
      >
        {isRunning ? 'Pause' : 'Resume'}
      </button>
    </div>
  );
};

export { CountdownTimer, CountUpTimer };
