'use client';

import * as React from 'react';
import { cn } from '../cn';
import { ClockIcon, CheckIcon, CircleIcon } from '@muzammil328/icon';

interface TimelineItem {
  id: string | number;
  title: string;
  description?: string;
  date?: string;
  icon?: React.ReactNode;
  status?: 'completed' | 'current' | 'pending' | 'failed';
}

interface TimelineProps extends React.HTMLAttributes<HTMLDivElement> {
  items: TimelineItem[];
  orientation?: 'vertical' | 'horizontal';
  showConnector?: boolean;
  onItemClick?: (item: TimelineItem) => void;
}

const Timeline: React.FC<TimelineProps> = ({
  items,
  className,
  orientation = 'vertical',
  showConnector = true,
  onItemClick,
  ...props
}) => {
  const isVertical = orientation === 'vertical';

  const getStatusIcon = (status?: TimelineItem['status']) => {
    switch (status) {
      case 'completed':
        return <CheckIcon className="h-4 w-4 text-white" />;
      case 'current':
        return <ClockIcon className="h-4 w-4 text-primary" />;
      case 'failed':
        return <CircleIcon className="h-4 w-4 text-destructive" />;
      default:
        return null;
    }
  };

  const getStatusStyles = (status?: TimelineItem['status']) => {
    switch (status) {
      case 'completed':
        return 'bg-primary border-primary';
      case 'current':
        return 'bg-background border-primary ring-2 ring-primary/20';
      case 'failed':
        return 'bg-background border-destructive';
      default:
        return 'bg-background border-muted';
    }
  };

  return (
    <div className={cn('flex', isVertical ? 'flex-col' : 'flex-row', className)} {...props}>
      {items.map((item, index) => (
        <div
          key={item.id}
          className={cn(
            'flex relative',
            isVertical ? 'flex-row' : 'flex-col',
            onItemClick && 'cursor-pointer hover:opacity-80'
          )}
          onClick={() => onItemClick?.(item)}
        >
          <div className="flex flex-col items-center">
            <div
              className={cn(
                'flex items-center justify-center w-8 h-8 rounded-full border-2 z-10',
                getStatusStyles(item.status)
              )}
            >
              {item.icon || getStatusIcon(item.status)}
            </div>
            {showConnector && index < items.length - 1 && (
              <div
                className={cn(
                  'flex-1',
                  isVertical ? 'w-0.5 h-full min-h-[40px]' : 'h-0.5 w-full min-w-[40px]',
                  item.status === 'completed' ? 'bg-primary' : 'bg-muted'
                )}
              />
            )}
          </div>
          <div
            className={cn(
              'flex flex-col',
              isVertical ? 'ml-4 pb-4' : 'mt-4 pl-0 pt-0 md:pt-4 md:pl-4'
            )}
          >
            {item.date && <span className="text-xs text-muted-foreground">{item.date}</span>}
            <h4 className="text-sm font-semibold">{item.title}</h4>
            {item.description && (
              <p className="text-sm text-muted-foreground mt-1">{item.description}</p>
            )}
          </div>
        </div>
      ))}
    </div>
  );
};

interface TimelineEvent {
  id: string | number;
  title: string;
  content?: string;
  time?: string;
  variant?: 'default' | 'success' | 'warning' | 'danger' | 'info';
}

interface TimelineEventsProps extends React.HTMLAttributes<HTMLDivElement> {
  events: TimelineEvent[];
  orientation?: 'left' | 'right' | 'alternate';
}

const TimelineEvents: React.FC<TimelineEventsProps> = ({
  events,
  className,
  orientation = 'left',
  ...props
}) => {
  const getVariantStyles = (variant?: TimelineEvent['variant']) => {
    switch (variant) {
      case 'success':
        return 'border-l-4 border-l-green-500 bg-green-50 dark:bg-green-950/20';
      case 'warning':
        return 'border-l-4 border-l-yellow-500 bg-yellow-50 dark:bg-yellow-950/20';
      case 'danger':
        return 'border-l-4 border-l-red-500 bg-red-50 dark:bg-red-950/20';
      case 'info':
        return 'border-l-4 border-l-blue-500 bg-blue-50 dark:bg-blue-950/20';
      default:
        return 'border-l-4 border-l-primary bg-muted/30';
    }
  };

  return (
    <div className={cn('space-y-4', className)} {...props}>
      {events.map((event, index) => (
        <div
          key={event.id}
          className={cn(
            'relative pb-4',
            orientation === 'right' ? 'pr-4 flex flex-row-reverse' : 'pl-4',
            getVariantStyles(event.variant),
            index === events.length - 1 && 'pb-0'
          )}
        >
          <div className="absolute left-[-5px] top-0 w-2.5 h-2.5 rounded-full bg-current opacity-50" />
          {event.time && <span className="text-xs text-muted-foreground">{event.time}</span>}
          <h4 className="text-sm font-medium">{event.title}</h4>
          {event.content && <p className="text-sm text-muted-foreground mt-1">{event.content}</p>}
        </div>
      ))}
    </div>
  );
};

export { Timeline, TimelineEvents };
export type { TimelineItem, TimelineEvent };
