'use client';

import * as React from 'react';
import { cn } from '../../cn';
import { AlertCircle } from 'lucide-react';

interface ImageProps extends React.ImgHTMLAttributes<HTMLImageElement> {
  src: string;
  alt: string;
  fallback?: React.ReactNode;
  errorFallback?: React.ReactNode;
  loading?: 'lazy' | 'eager';
  sizes?: string;
  widths?: number[];
}

const Image = React.forwardRef<HTMLImageElement, ImageProps>(
  (
    { className, src, alt, fallback, errorFallback, loading = 'lazy', sizes, ...props },
    ref
  ) => {
    const [isLoading, setIsLoading] = React.useState(true);
    const [isError, setIsError] = React.useState(false);
    const [currentSrc, setCurrentSrc] = React.useState(src);

    const handleLoad = () => {
      setIsLoading(false);
    };

    const handleError = () => {
      setIsError(true);
      setIsLoading(false);
    };

    React.useEffect(() => {
      setIsError(false);
      setIsLoading(true);
      setCurrentSrc(src);
    }, [src]);

    if (isError && errorFallback) {
      return <>{errorFallback}</>;
    }

    if (isError) {
      return (
        <div
          className={cn(
            'flex items-center justify-center bg-muted rounded-md min-h-[200px]',
            className
          )}
        >
          <div className="flex flex-col items-center gap-2 text-muted-foreground">
            <AlertCircle className="h-8 w-8" />
            <span className="text-sm">Failed to load image</span>
          </div>
        </div>
      );
    }

    return (
      <div className={cn('relative', className)}>
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center bg-muted rounded-md animate-pulse min-h-[200px]">
            {fallback || (
              <div className="h-4 w-4 rounded-full border-2 border-primary border-t-transparent animate-spin" />
            )}
          </div>
        )}
        <img
          ref={ref}
          src={currentSrc}
          alt={alt}
          loading={loading}
          sizes={sizes}
          onLoad={handleLoad}
          onError={handleError}
          className={cn(
            'transition-opacity duration-300',
            isLoading ? 'opacity-0' : 'opacity-100',
            className
          )}
          {...props}
        />
      </div>
    );
  }
);
Image.displayName = 'Image';

interface ResponsiveImageProps extends ImageProps {
  aspectRatio?: 'square' | 'video' | 'wide' | 'Portrait' | number;
}

const ResponsiveImage = React.forwardRef<HTMLImageElement, ResponsiveImageProps>(
  ({ className, aspectRatio = 'video', ...props }, ref) => {
    const aspectRatioClasses = {
      square: 'aspect-square',
      video: 'aspect-video',
      wide: 'aspect-[21/9]',
      portrait: 'aspect-[3/4]',
    };

    const aspectStyle = typeof aspectRatio === 'number' ? { aspectRatio: aspectRatio } : {};

    return (
      <div
        className={cn(
          'relative overflow-hidden',
          aspectRatioClasses[aspectRatio as keyof typeof aspectRatioClasses] || 'aspect-video',
          className
        )}
        style={aspectStyle}
      >
        <Image ref={ref} className="object-cover w-full h-full" {...props} />
      </div>
    );
  }
);
ResponsiveImage.displayName = 'ResponsiveImage';

export { Image, ResponsiveImage };
export type { ImageProps, ResponsiveImageProps };
