'use client';

import * as React from 'react';
import { cn } from '../../cn';
import { AlertCircle, Pause, Play, Volume2, VolumeX } from 'lucide-react';

interface VideoProps extends React.VideoHTMLAttributes<HTMLVideoElement> {
  src: string;
  poster?: string;
  fallback?: React.ReactNode;
}

const Video = React.forwardRef<HTMLVideoElement, VideoProps>(
  ({ className, src, poster, fallback, ...props }, ref) => {
    const videoRef = React.useRef<HTMLVideoElement>(null);
    const [isLoading, setIsLoading] = React.useState(true);
    const [isError, setIsError] = React.useState(false);
    const [isPlaying, setIsPlaying] = React.useState(false);
    const [isMuted, setIsMuted] = React.useState(false);

    const handleLoadedData = () => {
      setIsLoading(false);
    };

    const handleError = () => {
      setIsError(true);
      setIsLoading(false);
    };

    const togglePlay = () => {
      if (videoRef.current) {
        if (isPlaying) {
          videoRef.current.pause();
        } else {
          videoRef.current.play();
        }
        setIsPlaying(!isPlaying);
      }
    };

    const toggleMute = () => {
      if (videoRef.current) {
        videoRef.current.muted = !isMuted;
        setIsMuted(!isMuted);
      }
    };

    if (isError) {
      return (
        <div
          className={cn(
            'flex items-center justify-center bg-muted rounded-md min-h-[200px]',
            className
          )}
        >
          {fallback || (
            <div className="flex flex-col items-center gap-2 text-muted-foreground">
              <AlertCircle className="h-8 w-8" />
              <span className="text-sm">Failed to load video</span>
            </div>
          )}
        </div>
      );
    }

    return (
      <div className={cn('relative group', className)}>
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center bg-muted rounded-md animate-pulse min-h-[200px]">
            {fallback || (
              <div className="h-8 w-8 rounded-full border-2 border-primary border-t-transparent animate-spin" />
            )}
          </div>
        )}
        <video
          ref={e => {
            if (e) {
              (videoRef as React.MutableRefObject<HTMLVideoElement>).current = e;
              if (typeof ref === 'function') {
                ref(e);
              } else if (ref) {
                ref.current = e;
              }
            }
          }}
          src={src}
          poster={poster}
          onLoadedData={handleLoadedData}
          onError={handleError}
          onPlay={() => setIsPlaying(true)}
          onPause={() => setIsPlaying(false)}
          className={cn(
            'w-full rounded-md transition-opacity duration-300',
            isLoading ? 'opacity-0' : 'opacity-100'
          )}
          {...props}
        />
        <div className="absolute bottom-2 left-2 right-2 flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
          <button
            onClick={togglePlay}
            className="flex items-center justify-center w-8 h-8 bg-black/50 rounded-full hover:bg-black/70 text-white"
          >
            {isPlaying ? <Pause className="h-4 w-4" /> : <Play className="h-4 w-4" />}
          </button>
          <button
            onClick={toggleMute}
            className="flex items-center justify-center w-8 h-8 bg-black/50 rounded-full hover:bg-black/70 text-white"
          >
            {isMuted ? <VolumeX className="h-4 w-4" /> : <Volume2 className="h-4 w-4" />}
          </button>
        </div>
      </div>
    );
  }
);
Video.displayName = 'Video';

interface YouTubeVideoProps {
  videoId: string;
  className?: string;
  aspectRatio?: 'video' | 'wide' | 'square';
  autoplay?: boolean;
  start?: number;
  end?: number;
  mute?: boolean;
}

const YouTubeVideo: React.FC<YouTubeVideoProps> = ({
  videoId,
  className,
  aspectRatio = 'video',
  autoplay = false,
  start,
  end,
  mute = false,
}) => {
  const aspectRatioClasses = {
    square: 'aspect-square',
    video: 'aspect-video',
    wide: 'aspect-[21/9]',
  };

  const queryParams = new URLSearchParams();
  if (autoplay) queryParams.set('autoplay', '1');
  if (mute) queryParams.set('mute', '1');
  if (start) queryParams.set('start', start.toString());
  if (end) queryParams.set('end', end.toString());

  const src = `https://www.youtube.com/embed/${videoId}${queryParams.toString() ? `?${queryParams.toString()}` : ''}`;

  return (
    <div className={cn('relative w-full', aspectRatioClasses[aspectRatio], className)}>
      <iframe
        src={src}
        title="YouTube video player"
        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
        allowFullScreen
        className="absolute inset-0 w-full h-full rounded-md"
      />
    </div>
  );
};

export { Video, YouTubeVideo };
export type { VideoProps, YouTubeVideoProps };
