import * as React from 'react';
import { Slot } from '@radix-ui/react-slot';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '../cn';

// Variants
const badgeVariants = cva(
  'inline-flex items-center justify-center font-medium shrink-0 gap-1 px-2 py-0.5 text-xs transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 [&>svg]:size-3 [&>svg]:shrink-0',
  {
    variants: {
      variant: {
        primary_solid: 'bg-primary/10 dark:bg-gray/30 text-success-foreground border-none',
        primary_outline: 'bg-primary text-success-foreground border border-success',
        primary_subtle: 'bg-primary text-success-foreground border border-success',

        success_solid: 'bg-success text-success-foreground border-none',
        success_outline: 'bg-success text-success-foreground border !border-success-foreground',
        success_subtle: 'text-success-foreground border border-success-foreground',

        warning_solid: 'bg-warning text-warning-foreground border-none',
        warning_outline: 'bg-warning text-warning-foreground border !border-warning-foreground',
        warning_subtle: 'text-warning-foreground border border-warning-foreground',

        info_solid: 'bg-info text-info-foreground border-none',
        info_outline: 'bg-info text-info-foreground border !border-info-foreground',
        info_subtle: 'text-info-foreground border border-info-foreground',

        danger_solid: 'bg-danger text-danger-foreground border-none',
        danger_outline: 'bg-danger text-danger-foreground border !border-danger-foreground',
        danger_subtle: 'text-danger-foreground border border-danger-foreground',

        neutral_solid: 'bg-neutral text-neutral-foreground border-none',
        neutral_outline: 'bg-neutral text-neutral-foreground border !border-neutral-foreground',
        neutral_subtle: 'text-neutral-foreground border border-neutral-foreground',
      },
      size: {
        sm: 'px-2 py-0.5 text-xs',
        md: 'px-3 py-0.5 text-sm',
        lg: 'px-5 py-0.5 text-sm',
      },
      shape: {
        rounded: 'rounded-md',
        pill: 'rounded-full',
      },
      withDot: {
        true: 'pl-1.5 pr-2 gap-1.5',
      },
    },
    defaultVariants: {
      variant: 'primary_solid',
      size: 'sm',
      shape: 'rounded',
    },
  }
);

interface BadgeProps extends React.ComponentProps<'span'>, VariantProps<typeof badgeVariants> {
  asChild?: boolean;
  icon?: React.ReactNode;
}

function Badge({
  className,
  variant,
  size,
  shape,
  withDot,
  asChild = false,
  icon,
  children,
  ...props
}: BadgeProps) {
  const Comp = asChild ? Slot : 'span';

  return (
    <Comp
      data-slot="badge"
      className={cn(badgeVariants({ variant, size, shape, withDot }), className)}
      {...props}
    >
      {withDot && (
        <span
          className={cn(
            'size-2 rounded-full',
            (variant === 'success_solid' ||
              variant === 'success_outline' ||
              variant === 'success_subtle') &&
              'bg-success-foreground',
            (variant === 'warning_solid' ||
              variant === 'warning_outline' ||
              variant === 'warning_subtle') &&
              'bg-warning-foreground',
            (variant === 'info_solid' || variant === 'info_outline' || variant === 'info_subtle') &&
              'bg-info-foreground',
            (variant === 'danger_solid' ||
              variant === 'danger_outline' ||
              variant === 'danger_subtle') &&
              'bg-danger-foreground',
            (variant === 'neutral_solid' ||
              variant === 'neutral_outline' ||
              variant === 'neutral_subtle') &&
              'bg-neutral-foreground'
          )}
        />
      )}
      {icon && <span className="mr-[2px]">{icon}</span>}
      {children}
    </Comp>
  );
}

export { Badge, badgeVariants };
