import React from 'react';
import { cn } from '../../cn';
import { textVariants, linkVariants } from './TypographyVariants';
import type { VariantProps } from 'class-variance-authority';

type TextElement = 'p' | 'span' | 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';

type TextVariantProps = VariantProps<typeof textVariants>;
type LinkVariantProps = VariantProps<typeof linkVariants>;

type CustomizeProps = {
  textColor?: string;
  fontSize?: string;
  fontWeight?: string | number;
  lineHeight?: string;
  letterSpacing?: string;
};

type TextProps = {
  as?: TextElement;
  className?: string;
  children: React.ReactNode;
  customize?: CustomizeProps;
  lineHeight?: React.CSSProperties['lineHeight'];
} & TextVariantProps &
  React.HTMLAttributes<HTMLElement>;

export function Text({
  as = 'p',
  className,
  children,
  tone,
  size,
  weight,
  align,
  transform,
  clamp,
  italic,
  family,
  customize,
  lineHeight,
  style,
  ...props
}: TextProps) {
  const Component = as;

  return (
    <Component
      className={cn(
        textVariants({
          as,
          tone,
          size,
          weight,
          align,
          transform,
          clamp,
          italic,
          family,
        }),
        className
      )}
      style={{
        color: customize?.textColor,
        fontSize: customize?.fontSize,
        fontWeight: customize?.fontWeight,
        lineHeight: lineHeight ?? customize?.lineHeight,
        letterSpacing: customize?.letterSpacing,
        ...style,
      }}
      {...props}
    >
      {children}
    </Component>
  );
}

type LinkCustomizeProps = {
  textColor?: string;
  fontSize?: string;
  fontWeight?: string | number;
  textDecoration?: string;
};

type LinkProps = {
  href: string;
  title?: string;
  target?: React.HTMLAttributeAnchorTarget;
  className?: string;
  children: React.ReactNode;
  customize?: LinkCustomizeProps;
} & LinkVariantProps &
  React.AnchorHTMLAttributes<HTMLAnchorElement>;

export function Link({
  href,
  title,
  target = '_self',
  className,
  children,
  tone,
  size,
  weight,
  underline,
  customize,
  style,
  ...props
}: LinkProps) {
  return (
    <a
      href={href}
      title={title}
      aria-label={title}
      target={target}
      className={cn(
        linkVariants({
          tone,
          size,
          weight,
          underline,
        }),
        className
      )}
      style={{
        color: customize?.textColor,
        fontSize: customize?.fontSize,
        fontWeight: customize?.fontWeight,
        textDecoration: customize?.textDecoration,
        ...style,
      }}
      {...props}
    >
      {children}
    </a>
  );
}

export const Heading1 = (props: Omit<TextProps, 'as'>) => <Text as="h1" {...props} />;
export const Heading2 = (props: Omit<TextProps, 'as'>) => <Text as="h2" {...props} />;
export const Heading3 = (props: Omit<TextProps, 'as'>) => <Text as="h3" {...props} />;
export const Heading4 = (props: Omit<TextProps, 'as'>) => <Text as="h4" {...props} />;
export const Heading5 = (props: Omit<TextProps, 'as'>) => <Text as="h5" {...props} />;
export const Heading6 = (props: Omit<TextProps, 'as'>) => <Text as="h6" {...props} />;
export const Para = (props: Omit<TextProps, 'as'>) => <Text as="p" {...props} />;
export const Span = (props: Omit<TextProps, 'as'>) => <Text as="span" {...props} />;
