'use client';

import * as React from 'react';
import { cn } from '../../cn';
import { AlertCircle, ExternalLink, Loader2 } from 'lucide-react';

interface IframeProps extends React.IframeHTMLAttributes<HTMLIFrameElement> {
  src: string;
  title: string;
  fallback?: React.ReactNode;
  loading?: 'lazy' | 'eager';
}

const Iframe = React.forwardRef<HTMLIFrameElement, IframeProps>(
  ({ className, src, title, fallback, loading = 'lazy', ...props }, ref) => {
    const [isLoading, setIsLoading] = React.useState(true);
    const [isError, setIsError] = React.useState(false);

    const handleLoad = () => {
      setIsLoading(false);
    };

    const handleError = () => {
      setIsError(true);
      setIsLoading(false);
    };

    if (isError) {
      return (
        <div
          className={cn(
            'flex items-center justify-center bg-muted rounded-md min-h-[200px]',
            className
          )}
        >
          {fallback || (
            <div className="flex flex-col items-center gap-2 text-muted-foreground">
              <AlertCircle className="h-8 w-8" />
              <span className="text-sm">Failed to load content</span>
            </div>
          )}
        </div>
      );
    }

    return (
      <div className={cn('relative w-full', className)}>
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center bg-muted rounded-md min-h-[200px]">
            {fallback || <Loader2 className="h-8 w-8 animate-spin text-primary" />}
          </div>
        )}
        <iframe
          ref={ref}
          src={src}
          title={title}
          loading={loading}
          onLoad={handleLoad}
          onError={handleError}
          className={cn(
            'w-full rounded-md transition-opacity duration-300 border-0',
            isLoading ? 'opacity-0' : 'opacity-100'
          )}
          style={{ minHeight: '200px' }}
          {...props}
        />
      </div>
    );
  }
);
Iframe.displayName = 'Iframe';

interface ResponsiveIframeProps extends Omit<IframeProps, 'width' | 'height'> {
  aspectRatio?: 'video' | 'square' | 'wide' | 'tall';
}

const ResponsiveIframe: React.FC<ResponsiveIframeProps> = ({
  className,
  aspectRatio = 'video',
  ...props
}) => {
  const aspectRatioClasses = {
    square: 'aspect-square',
    video: 'aspect-video',
    wide: 'aspect-[21/9]',
    tall: 'aspect-[3/4]',
  };

  return (
    <div className={cn('relative w-full', aspectRatioClasses[aspectRatio], className)}>
      <Iframe className="absolute inset-0 w-full h-full" {...props} />
    </div>
  );
};
ResponsiveIframe.displayName = 'ResponsiveIframe';

interface EmbedProps {
  url: string;
  title?: string;
  className?: string;
}

const Embed: React.FC<EmbedProps> = ({ url, title = 'Embedded content', className }) => {
  const getcontracts = (url: string) => {
    try {
      return new URL(url).hostname.replace('www.', '');
    } catch {
      return 'unknown';
    }
  };

  const contracts = getcontracts(url);

  const isYouTube = contracts.includes('youtube') || contracts.includes('youtu.be');
  const isVimeo = contracts.includes('vimeo');

  if (isYouTube) {
    const videoId = url.includes('youtu.be')
      ? url.split('/').pop()
      : new URL(url).searchParams.get('v');

    if (videoId) {
      return <YouTubeEmbed videoId={videoId} title={title} className={className} />;
    }
  }

  if (isVimeo) {
    const videoId = url.split('/').pop();
    if (videoId) {
      return <VimeoEmbed videoId={videoId} title={title} className={className} />;
    }
  }

  return <Iframe src={url} title={title} className={cn('aspect-video', className)} />;
};

const YouTubeEmbed: React.FC<{ videoId: string; title?: string; className?: string }> = ({
  videoId,
  title = 'YouTube video',
  className,
}) => (
  <div className={cn('relative w-full aspect-video', className)}>
    <iframe
      src={`https://www.youtube.com/embed/${videoId}`}
      title={title}
      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
      allowFullScreen
      className="absolute inset-0 w-full h-full rounded-md"
    />
  </div>
);

const VimeoEmbed: React.FC<{ videoId: string; title?: string; className?: string }> = ({
  videoId,
  title = 'Vimeo video',
  className,
}) => (
  <div className={cn('relative w-full aspect-video', className)}>
    <iframe
      src={`https://player.vimeo.com/video/${videoId}`}
      title={title}
      allow="autoplay; fullscreen; picture-in-picture"
      allowFullScreen
      className="absolute inset-0 w-full h-full rounded-md"
    />
  </div>
);

const OpenInNewTab: React.FC<{ url: string; className?: string }> = ({ url, className }) => (
  <a
    href={url}
    target="_blank"
    rel="noopener noreferrer"
    className={cn(
      'flex items-center gap-2 text-sm text-muted-foreground hover:text-primary transition-colors',
      className
    )}
  >
    <ExternalLink className="h-4 w-4" />
    Open in new tab
  </a>
);

export { Iframe, ResponsiveIframe, Embed, OpenInNewTab };
export type { IframeProps, ResponsiveIframeProps, EmbedProps };
