'use client';

import * as React from 'react';
import { cn } from '../cn';
import { ChevronIconLeft, ChevronIconRight } from '@muzammil328/icon';

interface CarouselProps extends React.HTMLAttributes<HTMLDivElement> {
  opts?: {
    align?: 'start' | 'center' | 'end';
    loop?: boolean;
  };
  plugins?: [];
  orientation?: 'horizontal' | 'vertical';
}

const CarouselContext = React.createContext<{
  carouselRef: React.RefObject<HTMLDivElement | null>;
  orientation: 'horizontal' | 'vertical';
  canScrollPrev: boolean;
  canScrollNext: boolean;
  scrollPrev: () => void;
  scrollNext: () => void;
}>({
  carouselRef: { current: null },
  orientation: 'horizontal',
  canScrollPrev: false,
  canScrollNext: false,
  scrollPrev: () => { /* empty */ },
  scrollNext: () => { /* empty */ },
});

const Carousel = React.forwardRef<HTMLDivElement, CarouselProps>(
  ({ className, opts, orientation = 'horizontal', children, ...props }, ref) => {
    const carouselRef = React.useRef<HTMLDivElement>(null);
    const [canScrollPrev, setCanScrollPrev] = React.useState(false);
    const [canScrollNext, setCanScrollNext] = React.useState(false);

    const scrollPrev = React.useCallback(() => {
      if (!carouselRef.current) return;
      const scrollAmount =
        opts?.align === 'center'
          ? carouselRef.current.offsetWidth / 2
          : carouselRef.current.offsetWidth;
      carouselRef.current.scrollBy({ left: -scrollAmount, behavior: 'smooth' });
    }, [opts?.align]);

    const scrollNext = React.useCallback(() => {
      if (!carouselRef.current) return;
      const scrollAmount =
        opts?.align === 'center'
          ? carouselRef.current.offsetWidth / 2
          : carouselRef.current.offsetWidth;
      carouselRef.current.scrollBy({ left: scrollAmount, behavior: 'smooth' });
    }, [opts?.align]);

    React.useEffect(() => {
      const carousel = carouselRef.current;
      if (!carousel) return;

      const checkScroll = () => {
        const { scrollLeft, scrollWidth, clientWidth } = carousel;
        setCanScrollPrev(scrollLeft > 0);
        setCanScrollNext(scrollLeft < scrollWidth - clientWidth - 1);
      };

      carousel.addEventListener('scroll', checkScroll);
      checkScroll();
      return () => carousel.removeEventListener('scroll', checkScroll);
    }, [opts?.loop]);

    return (
      <CarouselContext.Provider
        value={{
          carouselRef,
          orientation,
          canScrollPrev,
          canScrollNext,
          scrollPrev,
          scrollNext,
        }}
      >
        <div ref={ref} className={cn('relative', className)} {...props}>
          {children}
        </div>
      </CarouselContext.Provider>
    );
  }
);
Carousel.displayName = 'Carousel';

const CarouselContent = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const { orientation } = React.useContext(CarouselContext);

    return (
      <div
        ref={ref}
        className={cn('flex', orientation === 'horizontal' ? 'flex-row' : 'flex-col', className)}
        {...props}
      />
    );
  }
);
CarouselContent.displayName = 'CarouselContent';

const CarouselItem = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const { orientation } = React.useContext(CarouselContext);

    return (
      <div
        ref={ref}
        className={cn(
          'min-w-0 shrink-0',
          orientation === 'horizontal' ? 'w-full' : 'h-full',
          className
        )}
        {...props}
      />
    );
  }
);
CarouselItem.displayName = 'CarouselItem';

const CarouselPrevious = React.forwardRef<HTMLButtonElement, React.ComponentProps<'button'>>(
  ({ className, ...props }, ref) => {
    const { canScrollPrev, scrollPrev } = React.useContext(CarouselContext);

    return (
      <button
        ref={ref}
        className={cn(
          'absolute h-8 w-8 rounded-full flex items-center justify-center',
          'border bg-background shadow-sm hover:bg-accent',
          'disabled:opacity-50 cursor-pointer',
          'left-4 top-1/2 -translate-y-1/2',
          className
        )}
        disabled={!canScrollPrev}
        onClick={scrollPrev}
        {...props}
      >
        <ChevronIconLeft className="h-4 w-4" />
        <span className="sr-only">Previous slide</span>
      </button>
    );
  }
);
CarouselPrevious.displayName = 'CarouselPrevious';

const CarouselNext = React.forwardRef<HTMLButtonElement, React.ComponentProps<'button'>>(
  ({ className, ...props }, ref) => {
    const { canScrollNext, scrollNext } = React.useContext(CarouselContext);

    return (
      <button
        ref={ref}
        className={cn(
          'absolute h-8 w-8 rounded-full flex items-center justify-center',
          'border bg-background shadow-sm hover:bg-accent',
          'disabled:opacity-50 cursor-pointer',
          'right-4 top-1/2 -translate-y-1/2',
          className
        )}
        disabled={!canScrollNext}
        onClick={scrollNext}
        {...props}
      >
        <ChevronIconRight className="h-4 w-4" />
        <span className="sr-only">Next slide</span>
      </button>
    );
  }
);
CarouselNext.displayName = 'CarouselNext';

const CarouselDots = ({ count }: { count: number }) => {
  const { carouselRef } = React.useContext(CarouselContext);
  const [activeIndex, setActiveIndex] = React.useState(0);

  React.useEffect(() => {
    const carousel = carouselRef.current;
    if (!carousel) return;

    const handleScroll = () => {
      const { scrollLeft, clientWidth } = carousel;
      const newIndex = Math.round(scrollLeft / clientWidth);
      setActiveIndex(newIndex);
    };

    carousel.addEventListener('scroll', handleScroll);
    return () => carousel.removeEventListener('scroll', handleScroll);
  }, [carouselRef]);

  return (
    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-2">
      {Array.from({ length: count }).map((_, i) => (
        <button
          key={i}
          className={cn(
            'h-2 w-2 rounded-full transition-all',
            i === activeIndex ? 'bg-primary w-4' : 'bg-muted-foreground/30'
          )}
          onClick={() => {
            carouselRef.current?.scrollTo({
              left: i * (carouselRef.current?.clientWidth || 0),
              behavior: 'smooth',
            });
          }}
        />
      ))}
    </div>
  );
};

export { Carousel, CarouselContent, CarouselItem, CarouselPrevious, CarouselNext, CarouselDots };
