'use client';
import React from 'react';
import { cn } from '../cn';
import { LoaderSpinner } from '@muzammil328/icon';
import { Skeleton } from './feedback/skeleton';

interface DropdownLoaderProps {
  isLoading?: boolean;
  error?: Error | null;
  isEmpty?: boolean;
  emptyMessage?: string;
  errorMessage?: string;
  loadingHeight?: string;
  className?: string;
  children?: React.ReactNode;
}

export function DropdownLoader({
  isLoading,
  error,
  isEmpty,
  emptyMessage = 'No options found.',
  errorMessage,
  loadingHeight = 'h-10',
  className,
  children,
}: DropdownLoaderProps) {
  if (isLoading) {
    return <Skeleton className={cn('rounded-md', loadingHeight, className)} />;
  }

  if (error) {
    return (
      <p className={cn('text-sm text-destructive', className)}>
        {errorMessage || error.message || 'An error occurred'}
      </p>
    );
  }

  if (isEmpty) {
    return <p className={cn('text-sm text-muted-foreground', className)}>{emptyMessage}</p>;
  }

  return <>{children}</>;
}

interface ButtonLoaderProps {
  isLoading?: boolean;
  loadingText?: string;
  children: React.ReactNode;
  className?: string;
}

export function ButtonLoader({ isLoading, loadingText, children, className }: ButtonLoaderProps) {
  if (!isLoading) {
    return <>{children}</>;
  }

  return (
    <span className={cn('flex items-center gap-2', className)}>
      <LoaderSpinner className="h-4 w-4 animate-spin" />
      {loadingText && <span>{loadingText}</span>}
    </span>
  );
}

interface AsyncResultProps<T> {
  data: T | undefined;
  isLoading?: boolean;
  error?: Error | null;
  loadingHeight?: string;
  render: (data: NonNullable<T>) => React.ReactNode;
  loadingPlaceholder?: React.ReactNode;
  errorPlaceholder?: React.ReactNode;
  emptyPlaceholder?: React.ReactNode;
  emptyCondition?: (data: T | undefined) => boolean;
}

export function AsyncResult<T>({
  data,
  isLoading,
  error,
  loadingHeight = 'h-20',
  render,
  loadingPlaceholder,
  errorPlaceholder,
  emptyPlaceholder,
  emptyCondition = d => !d || (Array.isArray(d) && d.length === 0),
}: AsyncResultProps<T>) {
  if (isLoading) {
    return loadingPlaceholder ?? <Skeleton className={cn('rounded-md', loadingHeight)} />;
  }

  if (error) {
    return (
      errorPlaceholder ?? (
        <p className="text-sm text-destructive">Failed to load: {error.message}</p>
      )
    );
  }

  if (emptyCondition(data)) {
    return emptyPlaceholder ?? <p className="text-sm text-muted-foreground">No data available.</p>;
  }

  return render(data as NonNullable<T>);
}
