'use client';
import React from 'react';
import { useState } from 'react';
import { CodeBlockProps } from './types';

export function CodeBlock({
  code,
  language,
  filename,
  theme,
}: CodeBlockProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(code);
      setCopied(true);
      setTimeout(() => setCopied(false), 1500);
    } catch {
      setCopied(false);
    }
  };

  return (
    <div className={theme?.code?.container}>
      <div className={theme?.code?.header}>
        <span>{filename || language || 'Code'}</span>
        <button onClick={handleCopy} className={theme?.code?.button}>
          {copied ? 'Copied' : 'Copy'}
        </button>
      </div>

      <pre className={theme?.code?.pre}>
        <code className={`language-${language || 'text'}`}>{code}</code>
      </pre>
    </div>
  );
}