'use client';

import * as React from 'react';
import { cn } from '../cn';
import { ChevronIconLeft, ChevronIconRight, CheckIcon } from '@muzammil328/icon';

interface Step {
  id: string | number;
  title: string;
  description?: string;
}

interface StepperProps extends React.HTMLAttributes<HTMLDivElement> {
  steps: Step[];
  currentStep: number;
  onStepChange?: (step: number) => void;
  orientation?: 'horizontal' | 'vertical';
  showButtons?: boolean;
  onNext?: () => void;
  onBack?: () => void;
  nextDisabled?: boolean;
  backDisabled?: boolean;
  finishText?: string;
  nextText?: string;
  backText?: string;
}

const Stepper: React.FC<StepperProps> = ({
  steps,
  currentStep,
  onStepChange,
  orientation = 'horizontal',
  showButtons = true,
  onNext,
  onBack,
  nextDisabled = false,
  backDisabled = false,
  finishText = 'Finish',
  nextText = 'Next',
  backText = 'Back',
  className,
  ...props
}) => {
  const isVertical = orientation === 'vertical';

  const handleStepClick = (index: number) => {
    if (index < currentStep) {
      onStepChange?.(index);
    }
  };

  const isLastStep = currentStep === steps.length - 1;
  const isFirstStep = currentStep === 0;

  return (
    <div className={cn('w-full', className)} {...props}>
      <div className={cn('flex', isVertical ? 'flex-col' : 'items-center justify-between w-full')}>
        {steps.map((step, index) => {
          const isCompleted = index < currentStep;
          const isCurrent = index === currentStep;
          const isClickable = index < currentStep;

          return (
            <div
              key={step.id}
              className={cn(
                'flex relative',
                isVertical ? 'flex-row items-start' : 'flex-col items-center flex-1',
                !isVertical && index !== steps.length - 1 && 'flex-1'
              )}
            >
              <button
                type="button"
                onClick={() => handleStepClick(index)}
                disabled={!isClickable}
                className={cn(
                  'flex items-center justify-center rounded-full border-2 transition-all z-10',
                  isVertical ? 'w-10 h-10' : 'w-10 h-10',
                  isCompleted && 'bg-primary border-primary',
                  isCurrent && 'bg-background border-primary',
                  !isCompleted && !isCurrent && 'bg-background border-muted',
                  isClickable && 'cursor-pointer hover:border-primary/80',
                  !isClickable && 'cursor-default'
                )}
              >
                {isCompleted ? (
                  <CheckIcon className="h-5 w-5 text-primary-foreground" />
                ) : (
                  <span
                    className={cn(
                      'text-sm font-semibold',
                      isCurrent ? 'text-primary' : 'text-muted-foreground'
                    )}
                  >
                    {index + 1}
                  </span>
                )}
              </button>

              {!isVertical && index !== steps.length - 1 && (
                <div
                  className={cn(
                    'flex-1 h-0.5 mx-2 transition-colors',
                    isCompleted ? 'bg-primary' : 'bg-muted'
                  )}
                />
              )}

              {isVertical && index !== steps.length - 1 && (
                <div
                  className={cn(
                    'absolute left-5 top-10 w-0.5 h-[calc(100%-20px)] -translate-x-1/2 transition-colors',
                    isCompleted ? 'bg-primary' : 'bg-muted'
                  )}
                />
              )}

              <div
                className={cn(
                  'flex flex-col',
                  isVertical ? 'ml-4 min-h-[60px]' : 'items-center mt-2'
                )}
              >
                <span
                  className={cn(
                    'text-sm font-medium',
                    isCurrent
                      ? 'text-primary'
                      : isCompleted
                        ? 'text-foreground'
                        : 'text-muted-foreground'
                  )}
                >
                  {step.title}
                </span>
                {step.description && (
                  <span className="text-xs text-muted-foreground mt-0.5 hidden md:block">
                    {step.description}
                  </span>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {showButtons && (
        <div className={cn('flex justify-between mt-6', isVertical && 'ml-14')}>
          <button
            type="button"
            onClick={onBack}
            disabled={isFirstStep || backDisabled}
            className={cn(
              'flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-md border transition-colors',
              'hover:bg-accent hover:text-accent-foreground',
              (isFirstStep || backDisabled) && 'opacity-50 cursor-not-allowed'
            )}
          >
            <ChevronIconLeft className="h-4 w-4" />
            {backText}
          </button>

          {isLastStep ? (
            <button
              type="button"
              onClick={onNext}
              disabled={nextDisabled}
              className={cn(
                'flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-md bg-primary text-primary-foreground transition-colors',
                'hover:bg-primary/90',
                nextDisabled && 'opacity-50 cursor-not-allowed'
              )}
            >
              {finishText}
              <CheckIcon className="h-4 w-4" />
            </button>
          ) : (
            <button
              type="button"
              onClick={onNext}
              disabled={nextDisabled}
              className={cn(
                'flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-md bg-primary text-primary-foreground transition-colors',
                'hover:bg-primary/90',
                nextDisabled && 'opacity-50 cursor-not-allowed'
              )}
            >
              {nextText}
              <ChevronIconRight className="h-4 w-4" />
            </button>
          )}
        </div>
      )}
    </div>
  );
};

interface StepIndicatorProps extends React.HTMLAttributes<HTMLDivElement> {
  totalSteps: number;
  currentStep: number;
  size?: 'sm' | 'md' | 'lg';
}

const StepIndicator: React.FC<StepIndicatorProps> = ({
  totalSteps,
  currentStep,
  size = 'md',
  className,
  ...props
}) => {
  const sizeClasses = {
    sm: 'w-4 h-4',
    md: 'w-6 h-6',
    lg: 'w-8 h-8',
  };

  return (
    <div className={cn('flex items-center gap-1', className)} {...props}>
      {Array.from({ length: totalSteps }).map((_, index) => {
        const isCompleted = index < currentStep;
        const isCurrent = index === currentStep;

        return (
          <div
            key={index}
            className={cn(
              'rounded-full transition-all',
              sizeClasses[size],
              isCompleted && 'bg-primary',
              isCurrent && 'bg-primary/50 animate-pulse',
              !isCompleted && !isCurrent && 'bg-muted'
            )}
          />
        );
      })}
    </div>
  );
};

export { Stepper, StepIndicator };
export type { Step };
